<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  body{font-family:Arial,sans-serif;margin:0;padding:20px;background:#f4f6fa;}
  .board{display:flex;gap:15px;}
  .column{background:white;border-radius:5px;flex:1;display:flex;flex-direction:column;height:80vh;}
  .header{padding:10px;font-weight:bold;background:#e0e3eb;border-bottom:1px solid #d0d4da;display:flex;justify-content:space-between;align-items:center;}
  .count{background:#1976d2;color:white;padding:2px 6px;border-radius:12px;font-size:12px;}
  .cards{flex:1;padding:10px;overflow-y:auto;}
  .card{background:#fff;margin-bottom:8px;padding:10px;border-radius:4px;box-shadow:0 1px 3px rgba(0,0,0,.1);display:flex;justify-content:space-between;align-items:center;}
  .card:hover{box-shadow:0 2px 6px rgba(0,0,0,.15);}
  .card-del{background:#ff5252;color:white;border:none;padding:4px 8px;border-radius:3px;font-size:12px;cursor:pointer;}
  #new-card{width:calc(100% - 80px);padding:6px;margin-right:5px;}
  #add-card{padding:6px 10px;background:#1976d2;color:white;border:none;border-radius:3px;cursor:pointer;}
</style>
</head>
<body>

<h1>Kanban Board</h1>

<div style="margin-bottom:15px;">
  <input type="text" id="new-card" placeholder="New task...">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div id="col-todo" class="column" ondragover="allowDrop(event)" ondrop="dropCard(event)">
    <div class="header"><span>To Do</span><span class="count">0</span></div>
    <div class="cards"></div>
  </div>
  <div id="col-doing" class="column" ondragover="allowDrop(event)" ondrop="dropCard(event)">
    <div class="header"><span>Doing</span><span class="count">0</span></div>
    <div class="cards"></div>
  </div>
  <div id="col-done" class="column" ondragover="allowDrop(event)" ondrop="dropCard(event)">
    <div class="header"><span>Done</span><span class="count">0</span></div>
    <div class="cards"></div>
  </div>
</div>

<script>
(function(){
  const STORAGE_KEY = 'kanban-board-state';
  let boardState = {todo: [], doing: [], done: []};

  function loadState() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) boardState = JSON.parse(data);
  }

  function saveState() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(boardState));
  }

  function updateCounts() {
    ['todo','doing','done'].forEach(col=>{
      const countEl = document.querySelector(`#col-${col} .count`);
      countEl.textContent = boardState[col].length;
    });
  }

  function createCardElement(title) {
    const card = document.createElement('div');
    card.className = 'card';
    card.setAttribute('draggable', true);
    card.dataset.title = title;

    const span = document.createElement('span');
    span.textContent = title;

    const delBtn = document.createElement('button');
    delBtn.className = 'card-del';
    delBtn.textContent = '✕';
    delBtn.onclick = () => deleteCard(card);

    card.appendChild(span);
    card.appendChild(delBtn);

    card.ondragstart = (e)=>{ e.dataTransfer.setData('text/plain', title); e.dataTransfer.effectAllowed='move'; };

    return card;
  }

  function renderBoard() {
    ['todo','doing','done'].forEach(col=>{
      const container = document.querySelector(`#col-${col} .cards`);
      container.innerHTML = '';
      boardState[col].forEach(title=>container.appendChild(createCardElement(title)));
    });
    updateCounts();
  }

  function addNewCard() {
    const input = document.getElementById('new-card');
    const title = input.value.trim();
    if (!title) return;
    boardState.todo.push(title);
    saveState();
    renderBoard();
    input.value = '';
  }

  function deleteCard(cardEl) {
    const title = cardEl.dataset.title;
    ['todo','doing','done'].forEach(col=>{
      const idx = boardState[col].indexOf(title);
      if (idx>-1){ boardState[col].splice(idx,1); }
    });
    saveState();
    renderBoard();
  }

  function allowDrop(ev) { ev.preventDefault(); }

  function dropCard(ev) {
    ev.preventDefault();
    const title = ev.dataTransfer.getData('text/plain');
    if (!title) return;
    // remove from all columns
    ['todo','doing','done'].forEach(col=>{
      const idx = boardState[col].indexOf(title);
      if (idx>-1){ boardState[col].splice(idx,1); }
    });
    // add to target column
    const colId = ev.currentTarget.id.replace('col-','');
    boardState[colId].push(title);
    saveState();
    renderBoard();
  }

  document.getElementById('add-card').onclick = addNewCard;
  document.getElementById('new-card').onkeydown = e=>{ if(e.key==='Enter') addNewCard(); };

  loadState();
  renderBoard();
})();
</script>
</body>
</html>
